const path = require('path');
const { expect } = require('chai');
const PluginLoader = require('../../../src/core/PluginLoader');
const StageExecutor = require('../../../src/core/StageExecutor');

describe('PluginStage Integration: PluginA', () => {
  const context = {
    log: [],
    container: {},
    metadata: {},
    log:[]
  };

  before(() => {
    // Set plugin directory to include PluginA
    console.log (__dirname);

    PluginLoader.pluginDirs = [path.resolve(__dirname, '../../mocks/plugin')];
    PluginLoader.load();
  });

  it('should execute PluginA processors for Scan, DI, and Init stages', async () => {
    await StageExecutor.executeStage('Scan', context);
    await StageExecutor.executeStage('DI', context);
    await StageExecutor.executeStage('Init', context);

    expect(context.log).to.deep.equal([
      'PluginA: Scan stage executed',
      'PluginA: DI stage executed',
      'PluginA: Init stage executed'
    ]);

    expect(context.metadata.pluginA?.scanned).to.equal(true);
    expect(context.container.pluginAService).to.exist;
    expect(context.container.pluginAService.name).to.equal('PluginAService');
    expect(context.container.pluginAService.initialized).to.equal(true);
  });

  it('should not execute PluginA processors for unrelated stages', async () => {
    await StageExecutor.executeStage('VI', context);
    await StageExecutor.executeStage('Run', context);

    expect(context.log).to.not.include('PluginA: VI stage executed');
    expect(context.log).to.not.include('PluginA: Run stage executed');
  });
});